{{state_descriptions}}: {{
  "system_time": "Current simulation time in minutes from the start of the service day (e.g., 480 for 08:00 AM).",
  "fleet_status": "A list of objects containing vehicle_id, current_route, current_stop_index, and current_delay in minutes.",
  "active_disruptions": "List of current incidents (e.g., road closures, mechanical failures) affecting specific segments or vehicles.",
  "schedule_adherence_matrix": "A mapping of Trip IDs to their deviation from the planned timetable (positive for delays, negative for early arrivals).",
  "passenger_load_data": "Estimated passenger counts per vehicle and station to calculate the impact of delays."
}}
{action_set_definitions}: {
  "query_fleet_status": {
    "description": "Retrieves real-time status for specific vehicles, including their current route, location index, and delay magnitude.",
    "parameters": {
      "type": "object",
      "properties": {
        "vehicle_ids": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "List of vehicle identifiers to check (e.g., ['Train 505', 'Bus 99'])."
        }
      },
      "required": [
        "vehicle_ids"
      ]
    },
    "example_output": {
      "status": [
        {
          "vehicle_id": "Train 505",
          "current_delay": 15,
          "estimated_arrival_time": 510,
          "route": "Feeder-Alpha"
        }
      ]
    }
  },
  "get_regulatory_constraints": {
    "description": "Retrieves the mandatory safety and labor regulations applicable to a specific vehicle or hub, such as maximum hold times and driver rest requirements.",
    "parameters": {
      "type": "object",
      "properties": {
        "vehicle_id": {
          "type": "string",
          "description": "The ID of the vehicle to check constraints for."
        },
        "location_id": {
          "type": "string",
          "description": "The hub or station name."
        }
      },
      "required": [
        "vehicle_id",
        "location_id"
      ]
    },
    "example_output": {
      "max_legal_hold_minutes": 10,
      "labor_limit_exceeded": false,
      "safety_protocol_required": "Standard-Check-List-A"
    }
  },
  "check_operational_barriers": {
    "description": "Scans for active disruptions (road closures, mechanical failures) that might prevent a vehicle from safely holding or departing.",
    "parameters": {
      "type": "object",
      "properties": {
        "location_id": {
          "type": "string"
        },
        "vehicle_id": {
          "type": "string"
        }
      },
      "required": [
        "location_id",
        "vehicle_id"
      ]
    },
    "example_output": {
      "barriers": [
        "Mechanical inspection due",
        "Road block on Segment 5"
      ],
      "clearance_status": "blocked"
    }
  },
  "apply_transfer_protection_hold": {
    "description": "Executes a hold order on a distributor vehicle to wait for a feeder vehicle.",
    "parameters": {
      "type": "object",
      "properties": {
        "vehicle_id": {
          "type": "string",
          "description": "The ID of the vehicle to be held."
        },
        "hold_duration_minutes": {
          "type": "integer",
          "description": "Number of minutes to wait."
        },
        "reason": {
          "type": "string"
        }
      },
      "required": [
        "vehicle_id",
        "hold_duration_minutes",
        "reason"
      ]
    },
    "example_output": {
      "hold_confirmed": true,
      "new_departure_time": 520
    }
  },
  "resolve_labor_barrier": {
    "description": "Adjusts crew assignments or extends labor shifts to authorize a hold that would otherwise violate labor standards.",
    "parameters": {
      "type": "object",
      "properties": {
        "vehicle_id": {
          "type": "string"
        },
        "action_type": {
          "type": "string",
          "enum": [
            "extend_shift",
            "crew_swap",
            "overtime_auth"
          ]
        }
      },
      "required": [
        "vehicle_id",
        "action_type"
      ]
    },
    "example_output": {
      "labor_compliance_met": true
    }
  },
  "authorize_departure": {
    "description": "Finalizes the recovery process and issues the legal clearance for the vehicle to depart from the hub.",
    "parameters": {
      "type": "object",
      "properties": {
        "vehicle_id": {
          "type": "string"
        },
        "safety_confirmation_code": {
          "type": "string",
          "description": "Code obtained from safety checks."
        }
      },
      "required": [
        "vehicle_id",
        "safety_confirmation_code"
      ]
    },
    "example_output": {
      "departure_status": "authorized",
      "timestamp": 525
    }
  }
}
